const tripStart = new Date('2026-03-12T00:00:00');
const tripEnd = new Date('2026-04-08T00:00:00');
const now = new Date();

const cities = [
  { name:'Shanghai', start:'2026-03-13', end:'2026-03-16', country:'China', weather_lat:31.23, weather_lon:121.47 },
  { name:'Taipei', start:'2026-03-16', end:'2026-03-19', country:'Taiwan', weather_lat:25.03, weather_lon:121.57 },
  { name:'Bangkok', start:'2026-03-19', end:'2026-03-20', country:'Thailand', weather_lat:13.76, weather_lon:100.50 },
  { name:'Krabi', start:'2026-03-20', end:'2026-03-29', country:'Thailand', weather_lat:8.04, weather_lon:98.84 },
  { name:'Bangkok2', start:'2026-03-29', end:'2026-03-30', country:'Thailand', weather_lat:13.76, weather_lon:100.50 },
  { name:'Xi\'an', start:'2026-03-31', end:'2026-04-02', country:'China', weather_lat:34.34, weather_lon:108.94 },
  { name:'Beijing', start:'2026-04-02', end:'2026-04-07', country:'China', weather_lat:39.90, weather_lon:116.41 }
];

const daysUntilTrip = Math.ceil((tripStart - now) / 86400000);
const isOnTrip = now >= tripStart && now <= tripEnd;

let currentCity = null;
let nextCity = null;
if (isOnTrip) {
  for (const c of cities) {
    const s = new Date(c.start), e = new Date(c.end);
    if (now >= s && now < e) { currentCity = c; break; }
  }
  for (const c of cities) {
    if (new Date(c.start) > now) { nextCity = c; break; }
  }
}

return [{
  json: {
    daysUntilTrip,
    isOnTrip,
    currentCity: currentCity?.name || null,
    currentCountry: currentCity?.country || null,
    nextCity: nextCity?.name || null,
    nextCityDate: nextCity?.start || null,
    weather_lat: currentCity?.weather_lat || cities[0].weather_lat,
    weather_lon: currentCity?.weather_lon || cities[0].weather_lon,
    phase: isOnTrip ? 'ON_TRIP' : (daysUntilTrip > 0 ? 'PRE_TRIP' : 'POST_TRIP')
  }
}];

const items = $input.all();
const tripData = items[0]?.json || {};
const weather = items[1]?.json?.daily || {};
const rates = items[2]?.json?.rates || {};

const weatherIcons = {0:'☀️',1:'🌤',2:'⛅',3:'☁️',45:'🌫',48:'🌫',51:'🌦',61:'🌧',63:'🌧',65:'🌧️',71:'❄️',80:'🌦',95:'⛈'};
const wCode = weather.weathercode?.[0] || 0;
const wIcon = weatherIcons[wCode] || '🌡';

let message = '';

if (tripData.phase === 'PRE_TRIP') {
  message = `🌏 *ASIA TRIP — Briefing Diario*\n\n`;
  message += `⏱ *Faltan ${tripData.daysUntilTrip} días* para salir\n\n`;
  message += `💱 *Tasas hoy:*\n`;
  message += `🇨🇳 1€ = ¥${rates.CNY?.toFixed(2) || '?'}\n`;
  message += `🇹🇼 1€ = NT$${rates.TWD?.toFixed(2) || '?'}\n`;
  message += `🇹🇭 1€ = ฿${rates.THB?.toFixed(2) || '?'}\n`;
  message += `\n📋 *Recordatorio:* ¿Has comprado los hoteles de Taipei y Beijing?`;
} else if (tripData.phase === 'ON_TRIP') {
  const tempMax = weather.temperature_2m_max?.[0];
  const tempMin = weather.temperature_2m_min?.[0];
  const rainProb = weather.precipitation_probability_max?.[0];
  message = `🌏 *Buenos días desde ${tripData.currentCity}!*\n\n`;
  message += `${wIcon} *Tiempo hoy:* ${tempMin}°–${tempMax}°C`;
  if (rainProb > 30) message += ` | 🌧 ${rainProb}% lluvia`;
  message += `\n\n`;
  message += `💱 *Tasa del día:*\n`;
  if (tripData.currentCountry === 'China') message += `🇨🇳 1€ = ¥${rates.CNY?.toFixed(2) || '?'}\n`;
  if (tripData.currentCountry === 'Taiwan') message += `🇹🇼 1€ = NT$${rates.TWD?.toFixed(2) || '?'}\n`;
  if (tripData.currentCountry === 'Thailand') message += `🇹🇭 1€ = ฿${rates.THB?.toFixed(2) || '?'}\n`;
  if (tripData.nextCity) {
    message += `\n🗺 *Próximo destino:* ${tripData.nextCity} (${tripData.nextCityDate})`;
  }
} else {
  message = `🌏 *Asia Trip 2026* — ¡Viaje completado! 🎉`;
}

return [{ json: { message } }];
